<template>
  <v-container class="quiz-panel grey lighten-5">
    <template v-if="socket.connected">
      <v-row align="center" justify="center">
        <v-col class="text-center">
          <h2>Quiz Panel room:{{ currentRoom || '未連結' }}</h2>
        </v-col>
      </v-row>
      <v-row justify="center">
        <!-- (使用者的)問題面板 Start -->
        <v-col cols="12" md="6" lg="4">
          <!-- 問題列表 start -->
          <v-container class="grey lighten-3 mb-5">
            <v-row>
              <v-col class="text-center">
                <h1>問題列表</h1>
              </v-col>
            </v-row>
            <!-- quizlist start  -->
            <v-row align="center" justify="center">
              <v-col>
                <quiz-list-panel
                  :quiz-list="quizList"
                  @answerQuiz="answerQuiz"
                  @deleteQuiz="deleteQuiz"
                  @addQuizToRoom="addQuizInstanceToRoom"
                ></quiz-list-panel>
              </v-col>
            </v-row>
            <!-- quizList end-->
          </v-container>
          <!-- 問題列表 end -->
        </v-col>
        <!-- (使用者的)問題面板  End -->

        <!-- 建立問題的面板 start -->
        <v-col cols="12" md="6" lg="4">
          <v-container class="grey lighten-3">
            <v-row>
              <v-col>
                <new-quiz-panel dense @submit="submitNewQuiz"></new-quiz-panel>
              </v-col>
            </v-row>
          </v-container>
        </v-col>
        <!-- 建立問題的面板 end -->

        <!-- quizInRoom start  -->
        <v-col cols="12" lg="4">
          <v-row>
            <v-col class="text-center">
              <h1>Quiz in room {{ currentRoom }}</h1>
            </v-col>
          </v-row>
          <!-- quizInstanceList start  -->
          <v-row>
            <v-col
              v-for="(quiz, quizIndex) in quizInstanceList"
              :key="quizIndex"
              cols="12"
              lg="12"
            >
              <v-card>
                <v-card-title>{{ `Question ${quizIndex + 1}.` }}</v-card-title>
                <v-card-text>
                  <p class="body-1">{{ quiz.description }}</p>
                  <div class="card-option">
                    <v-btn
                      v-for="(option, optionIndex) in quiz.option"
                      :key="optionIndex"
                      class="mr-1 mb-1"
                      color="primary"
                      @click.prevent="answerQuiz(quizIndex, optionIndex)"
                    >
                      {{ `${option.text}` }}
                    </v-btn>
                  </div>
                </v-card-text>
                <v-divider></v-divider>
                <v-card-actions>
                  <v-spacer></v-spacer>
                  <v-btn
                    class=""
                    color="error"
                    @click.prevent="
                      deleteQuizInstanceInRoom(quiz.instanceId, currentRoom)
                    "
                    >刪除</v-btn
                  >
                </v-card-actions>
              </v-card>
            </v-col>
          </v-row>
          <!-- quizInstanceList end-->
        </v-col>
        <!-- quizInRoom End  -->
      </v-row>
    </template>
    <template v-else>
      <v-row justify="center" align="center">
        <v-col>
          <h4>connecting...</h4>
        </v-col>
      </v-row>
    </template>
  </v-container>
</template>

<script>
import { socketService } from '../services'
import { mapGetters } from 'vuex'
import QuizListPanel from '../components/QuizListPanel'
import NewQuizPanel from '../components/NewQuizPanel'

export default {
  components: {
    QuizListPanel,
    NewQuizPanel,
  },
  props: {
    roomName: {
      type: String,
      default: 'test',
    },
  },
  data() {
    return {
      socket: null,
      currentRoom: this.roomName,
      quizList: [],
      quizType: { TOF: 1, SELECT: 2 },
      quizTemplate: {
        description: 'Please enter some text',
        type: 1,
        option: [{ text: 'Option 1' }, { text: 'Option 2' }],
        answer: 0,
      },
      newQuiz: {},
      newQuizOption: '',
      quizInstanceList: [],
      selfUpdateInterval: null,
    }
  },
  computed: {
    ...mapGetters({
      currentUser: 'account/currentUser',
    }),
    quizTypeList: function() {
      return Object.entries(this.quizType).map(([text, value]) => ({
        text,
        value,
      }))
    },
  },
  watch: {
    roomName: function(newRoomName) {
      this.initNewQuiz()
      this.currentRoom = newRoomName
      this.socket.emit('setRoom', newRoomName)
      this.socket.emit('updateQuizList', { roomName: this.currentRoom })
    },
  },
  created() {
    const vm = this
    this.initNewQuiz()

    this.socket = socketService.toNamespace('quiz')

    this.socket.on('connect', () => {
      console.log('quizNamespace connected')
      // vm.socket.emit('setRoom', this.roomName)
      if (vm.roomName) {
        vm.$nextTick(() => {
          vm.socket.emit('setRoom', vm.roomName)
          vm.socket.emit('updateQuizList', {
            userId: vm.currentUser._id,
            roomName: vm.roomName,
          })
        })
      }
    })

    this.socket.on('setRoom', roomName => {
      console.log('setRoom: title=', roomName)
      vm.currentRoom = roomName
    })
    this.socket.on('answerQuiz', result => {
      console.log('answerQuiz::result =', result)
    })
    this.socket.on('deleteQuiz', result => {
      console.log('DeleteQuiz::result =', result)
      vm.socket.emit('updateQuizList', { userId: vm.currentUser._id })
    })
    this.socket.on('addQuizInstanceToRoom', ({ quizId, roomName }) => {
      console.log('addQuizInstanceToRoom::', { quizId, roomName })
      if (roomName === vm.currentRoom) {
        vm.socket.emit('updateQuizList', { roomName })
      }
    })
    this.socket.on('deleteQuizInstanceInRoom', ({ quizId, roomName }) => {
      console.log('deleteQuizInstanceInRoom::', { quizId, roomName })
      if (roomName === vm.currentRoom) {
        vm.socket.emit('updateQuizList', { roomName })
      }
    })
    this.socket.on('updateQuizList', ({ quizList, from }) => {
      console.log('updateQuizList::quizList=', { quizList, from })
      switch (from) {
        case 'user': {
          vm.updateQuizList(quizList)
          break
        }
        case 'room': {
          vm.updateQuizInstanceList(quizList)
          break
        }
      }
    })
    this.socket.on('errorMessage', error => {
      console.error(error)
    })
    this.socket.on('disconnect', () => {
      console.log('quizNamespace disconnected')
      vm.initNewQuiz()
      clearInterval(this.selfUpdateInterval)
    })
  },
  mounted() {},
  beforeDestroy() {
    this.socket.close()
    clearInterval(this.selfUpdateInterval)
  },
  methods: {
    // Quiz section
    initNewQuiz() {
      this.quizList = []
      this.quizInstanceList = []
      this.currentRoom = ''
      this.newQuiz = { ...this.quizTemplate }
      this.newQuizOption = ''
    },
    updateQuizList(quizList) {
      console.log('updateQuizList::', { quizList })
      this.quizList = quizList
    },
    answerQuiz(quizIndex, optionIndex) {
      const answerObject = {
        quizId: this.quizList[quizIndex].id,
        optionNumber: optionIndex,
        userId: this.currentUser._id,
      }
      console.log('answerQuiz::quizData =', answerObject)
      this.socket.emit('answerQuiz', answerObject)
    },
    deleteQuiz(quizIndex) {
      const deleteCondition = {
        quizId: this.quizList[quizIndex].id,
      }
      console.log('deleteQuiz::', { quizIndex, deleteCondition })
      this.socket.emit('deleteQuiz', deleteCondition)
    },
    addQuizOption() {
      const optionObject = {
        text: this.newQuizOption,
      }
      this.newQuiz.option.push(optionObject)
    },
    submitNewQuiz(newQuiz) {
      const quizAuthor = this.currentUser._id
      const newQuizData = {
        ...newQuiz,
        author: quizAuthor,
      }
      console.log('submitNewQuiz::newQuizData =', newQuizData)
      this.socket.emit('newQuiz', newQuizData)
    },
    // Quiz section

    // Quiz Instance section
    updateQuizInstanceList(quizList) {
      console.log('updateQuizInstanceList::', quizList)
      this.quizInstanceList = quizList
    },
    addQuizInstanceToRoom(quizIndex) {
      const targetData = {
        roomName: this.currentRoom,
        quizData: this.quizList[quizIndex],
      }
      console.log('addQuizInstanceToRoom::socketSetting =', targetData)
      this.socket.emit('addQuizInstanceToRoom', targetData)
    },
    deleteQuizInstanceInRoom(quizInstanceId, roomName) {
      const targetData = {
        roomName,
        quizId: quizInstanceId,
      }
      console.log('deleteQuizInstanceInRoom::socketSetting =', targetData)
      this.socket.emit('deleteQuizInstanceInRoom', targetData)
    },
    // Quiz Instance section
  },
}
</script>
