const isProduciton = process.env.NODE_ENV === 'production'
// require('../../node_modules/comment-core-library/dist/CommentCoreLibrary.js')
// import 'comment-core-library/dist/CommentCoreLibrary.js'
const config = {
  jsUrl: `/js/CommentCoreLibrary${isProduciton ? '.min' : ''}.js`,
  // jsUrl: `../../node_modules/comment-core-library/dist/CommentCoreLibrary${
  //   isProduciton ? '.min' : ''
  // }.js`,
  cssUrl: '/css/style.css',
}

function loadScript(target = document.head) {
  return new Promise((resolve, reject) => {
    // Adding the script tag to the head as suggested before
    const newScript = document.createElement('script')
    newScript.type = 'text/javascript'
    newScript.src = config.jsUrl

    // Then bind the event to the callback function.
    // There are several events for cross browser compatibility.
    // script.onreadystatechange = resolve
    newScript.onload = resolve
    newScript.onerror = reject

    // Fire the loading
    target.appendChild(newScript)
  })
}

