<script>
import danmakuCCLMixin from '@/mixins/danmakuCCLMixin'
export default {
  mixins: [danmakuCCLMixin],
  props: {
    videoId: {
      type: String,
      default: () => {
        return ''
      },
    },
  },
  data: () => ({
    // --- Youtube ---
    // videoId: 'lG0Ys-2d4MA',
    playerVars: {
      controls: 1,
      rel: 0,
      // autoplay: 1,
    },
    isBuffering: false,
    bufferedPercentage: 0,
    updateLoadedFractionInterval: null,
    // --- Youtube ---

    // ---------------------------------------
    // --- Danmaku ---
    CM: null,
    // sourceTypes: {
    //   YOUTUBE: 0,
    //   SLIDEPLAYER: 1,
    // },
    danmakuText: '',
    danmakuSetting: {
      type: 1,
      size: 25,
      color: '#FFFFFF',
    },
    danmakuTypes: [
      { value: 1, text: '滾動', icon: 'mdi-pan-left' },
      { value: 5, text: '上方', icon: 'mdi-pan-up' },
      { value: 4, text: '下方', icon: 'mdi-pan-down' },
    ],
    danmakuSizes: [
      { value: 18, text: '小', suffix: 'small' },
      { value: 25, text: '標準', suffix: 'normal' },
      { value: 36, text: '大', suffix: 'large' },
    ],
    danmakuColors: [
      { value: '#FFFFFF' },
      { value: '#FDE53D' },
      { value: '#FF0026' },
      { value: '#00C3FC' },
      { value: '#A7FE39' },
      { value: '#B538FA' },
      { value: '#BEBEBE' },
      { value: '#FF9625' },
      { value: '#FF9496' },
      { value: '#0036FA' },
      { value: '#00FF91' },
      { value: '#FF02D3' },
    ],
    isSettingMenuActive: false,
    debounceSettingMenuActive: null,
    danmamkuLayerResizeIntervel: null,
  }),
  computed: {
    player() {
      return this.$refs.youtube.player
    },
  },
  mounted() {
    if (this.videoId !== '') {
      this.displayYotubePlayer = true
    }
    this.loadCommentManager()
    this.danmamkuLayerResizeIntervel = setInterval(() => {
      this.tryResizeDanmakuLayer()
    }, 1000)
    this.$emit('loaded', true)
  },
  beforeDestroy() {
    clearInterval(this.danmamkuLayerResizeIntervel)
  },
  methods: {
    async getPlayerStatus() {
      const playerStatus = {
        currentTime: await this.player.getCurrentTime(),
        playerState: await this.player.getPlayerState(),
        duration: await this.player.getDuration(),
        playbackRate: await this.player.getPlaybackRate(),
      }
      return playerStatus
    },
    async onPlaying() {
      console.log('o/ we are watching!!!')
      this.CM.start()
      const playerStatus = await this.getPlayerStatus()
      console.log(playerStatus)
      this.$emit('playing', playerStatus)
    },
    onPaused() {
      this.CM.stop()
    },
    onReady() {
      this.CM.clear()
    },
    async onBuffering() {
      this.isBuffering = true
      this.$emit('buffering', true)

      // console.log(await this.player.getVideoLoadedFraction())
      if (this.updateLoadedFractionInterval) {
        clearInterval(this.updateLoadedFractionInterval)
      }

      this.updateLoadedFractionInterval = setInterval(() => {
        this.player.getVideoLoadedFraction().then(loaded => {
          this.bufferedPercentage = loaded
        })
      }, 500)
    },
    playVideo() {
      this.player.playVideo()
      this.CM.start()
    },
    pauseVideo() {
      this.player.pauseVideo()
      this.CM.stop()
    },
    stopVideo() {
      this.player.stopVideo()
      this.CM.clear()
    },
    loadMediaSource(source) {
      const { YOUTUBE, SLIDEPLAYER } = this.sourceTypes
      switch (source) {
        case YOUTUBE: {
          this.loadYoutubeFrame()
          break
        }
        case SLIDEPLAYER: {
          break
        }
      }
    },
    async loadCommentManager() {
      if (typeof window.CommentManager === 'undefined') {
        // from mixin
        await this.loadCCL()
      }
      if (this.CM) {
        return
      }
      const danmakuStage = document.getElementsByClassName(
        'danmaku-player__danmu-layer'
      )[0]
      this.CM = new window.CommentManager(danmakuStage)
      window.CM = this.CM
      // default: css3 render
      this.CM.init()
      console.log('CM from player => %O on %O', this.CM, danmakuStage)
    },
    shootDanmaku(text, option = {}) {
      const { type, size, color } = this.danmakuSetting
      const danamkuObject = {
        ...option,
        size,
        text: text || this.danmakuText,
        color: parseInt(color.substring(1), 16),
        mode: type,
      }
      console.log(danamkuObject, option)
      this.CM.send(danamkuObject)
      this.danmakuText = ''
    },
    handleDanmakuInputEnter() {
      this.shootDanmaku()
    },
    handleSubmitBtnClick() {
      this.shootDanmaku()
    },
    tryResizeDanmakuLayer() {
      if (this.CM.width === this.CM.stage.offsetWidth) return
      const { offsetWidth, offsetHeight } = this.CM.stage
      this.CM.setBounds(offsetWidth, offsetHeight)
    },
    onMouseoverSettingBtn() {
      if (this.debounceSettingMenuActive) {
        clearTimeout(this.debounceSettingMenuActive)
        this.debounceSettingMenuActive = null
      }
      this.isSettingMenuActive = true
      this.debounceSettingMenuActive = setTimeout(() => {
        this.debounceSettingMenuActive = null
        this.isSettingMenuActive = false
      }, 1000)
    },
    onMouseoverMediaFrame() {
      console.log('onMouseoverMediaFrame')
    },
    isTypeActive(type) {
      return type.value === this.danmakuSetting.type
    },
    isSizeActive(size) {
      return size.value === this.danmakuSetting.size
    },
    isColorActive(color) {
      return color.value === this.danmakuSetting.color
    },
    handleTypeBtnClick(type) {
      this.danmakuSetting.type = type.value
    },
    handleSizeBtnClick(size) {
      this.danmakuSetting.size = size.value
    },
    handleColorBtnClick(color) {
      this.danmakuSetting.color = color.value
    },

    setPlaybackTime(time) {
      this.player.seekTo(time)
      this.playVideo()
    },
    setPlayerState(state) {
      console.log(this.$refs.youtube, state)
    },
    loadVideoById(settings) {
      this.player.loadVideoById({ ...settings })
      this.pauseVideo()
    },
  },
}
</script>

