import CCL from '@/plugins/danmakuCCL'

export default {
  data() {
    return {
      cclLoaded: false,
    }
  },
  methods: {
    loadCCL(target) {
      console.log('LoadCCL::target=', target)
      return CCL.load(target)
        .then(() => {
          this.cclLoaded = true
          console.log('LoadCCL::loading complete')
        })
        .catch(reason => {
          console.log('LoadCCL::error ->', reason)
        })
    },
  },
}
