<template>
  <v-card class="new-quiz-panel">
    <v-card-title>
      建立新問題
    </v-card-title>
    <v-card-text>
      <v-form>
        <v-textarea
          outlined
          class="mt-5"
          name="input-description"
          label="描述"
          placeholder="請輸入問題描述"
        ></v-textarea>

        <v-select dense :items="quizTypeList" label="題型" outlined></v-select>

        <v-list :dense="dense">
          <v-subheader>選項(請選擇答案)：</v-subheader>
          <v-list-item-group v-model="newQuiz.answer" mandatory color="primary">
            <v-slide-x-transition group>
              <v-list-item
                v-for="(option, optionIndex) in newQuiz.option"
                :key="option.text"
              >
                <v-list-item-content>
                  <v-list-item-title v-text="option.text"></v-list-item-title>
                </v-list-item-content>
                <v-list-item-action>
                  <v-btn
                    icon
                    color="error"
                    :small="dense"
                    @click="deleteQuizOption(optionIndex)"
                  >
                    <v-icon>mdi-close</v-icon>
                  </v-btn>
                </v-list-item-action>
              </v-list-item>
            </v-slide-x-transition>
          </v-list-item-group>
          <v-list-item>
            <v-list-item-content>
              <v-text-field
                v-model="newQuizOption"
                placeholder="新的選項"
                :dense="dense"
                @keyup.enter="addQuizOption"
              ></v-text-field>
            </v-list-item-content>
            <v-list-item-action>
              <v-btn small icon color="primary" @click="addQuizOption">
                <v-icon>mdi-plus</v-icon>
              </v-btn>
            </v-list-item-action>
          </v-list-item>
        </v-list>
      </v-form>
      <p>{{ newQuiz }}</p>
    </v-card-text>
    <v-divider></v-divider>
    <v-card-actions>
      <v-btn color="warning" @click="reset">重設</v-btn>
      <v-spacer></v-spacer>
      <v-btn color="success" @click="$emit('submit', newQuiz)">建立</v-btn>
    </v-card-actions>
  </v-card>
</template>

<script>
export default {
  props: {
    template: {
      type: Object,
      default: () => {
        return {
          description: 'Please enter some text',
          type: 1,
          option: [{ text: 'Option 1' }, { text: 'Option 2' }],
          answer: 0,
        }
      },
    },
    dense: {
      type: Boolean,
      default: () => false,
    },
  },
  data: () => ({
    quizType: { TOF: 1, SELECT: 2 },
    quizTemplate: {},
    newQuiz: {},
    newQuizOption: '',
    seletedOption: null,
  }),
  computed: {
    quizTypeList: function() {
      return Object.entries(this.quizType).map(([text, value]) => ({
        text,
        value,
      }))
    },
  },
  mounted() {
    this.quizTemplate = this.template
    this.$nextTick(() => {
      this.reset()
    })
  },
  methods: {
    reset() {
      this.newQuiz = { ...this.quizTemplate }
      this.newQuizOption = ''
    },
    addQuizOption() {
      const optionObject = {
        text: this.newQuizOption,
      }
      console.log('addQuizOption', optionObject)
      this.newQuiz.option.push(optionObject)
      this.newQuizOption = ''
    },
    deleteQuizOption(optionIndex) {
      console.log('deleteQuizOption', optionIndex)
      this.newQuiz.option.splice(optionIndex, 1)
    },
  },
}
</script>
