<template>
  <v-container>
    <v-row align="center" justify="center">
      <v-col cols="8" class="text-center">
        <h2>Danmaku Panel (room:{{ currentRoom || '未連結' }})</h2>
      </v-col>
      <v-col cols="4">
        <v-text-field
          v-model="videoId"
          label="影片ID"
          placeholder="VideoId"
        ></v-text-field>
        <v-btn color="primary" @click="changeVideo">更換</v-btn>
      </v-col>
    </v-row>
    <v-row>
      <v-col cols="12">
        <danmaku-player ref="player" @playing="onPlaying"></danmaku-player>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { socketService } from '../services'
import { mapGetters } from 'vuex'
import DanmakuPlayer from '@/components/DanmakuPlayer'
export default {
  components: { DanmakuPlayer },
  props: {
    roomName: {
      type: String,
      default: 'test',
    },
  },
  data: () => ({
    socket: null,
    currentRoom: null,
    videoId: 'lG0Ys-2d4MA',
  }),
  computed: {
    ...mapGetters({
      currentUser: 'account/currentUser',
    }),
  },
  created() {
    const vm = this
    this.socket = socketService.toNamespace('live')

    // this.currentRoom = 'test'
    this.socket.emit('setRoom', { roomName: this.roomName })

    this.socket.on('setRoom', respone => {
      console.log('DanamkuPanel::setRoom', respone)
      vm.currentRoom = respone.roomName
    })
    this.socket.on('checkRoom', respone => {
      console.log('DanamkuPanel::checkRoom', respone)
    })
    this.socket.on('syncPlaybackTime', data => {
      console.log('DanamkuPanel::syncPlaybackTime', data)
      const { time } = data
      vm.$refs.player.setPlaybackTime(time)
    })
    this.socket.on('syncPlayerState', data => {
      console.log('DanamkuPanel::syncPlayerState', data)
      const { state } = data
      vm.$refs.player.setPlayerState(state)
    })
    this.socket.on('syncPlayingVideo', data => {
      console.log('DanamkuPanel::syncPlayingVideo', data)
      const { videoId } = data
      vm.$refs.player.loadVideoById(videoId)
    })
  },
  methods: {
    onPlaying(status) {
      // if is host
      // for debug
      if (this.currentUser.role === 'student') return false
      const { currentTime, playerState } = status
      this.socket.emit('syncPlaybackTime', { targetTime: currentTime })
      this.socket.emit('syncPlayerState', { targetState: playerState })
    },
    changeVideo() {
      this.$refs.player.loadVideoById({ videoId: this.videoId })
      // this.$refs.player.setVideoId(this.videoId)
      this.socket.emit('syncPlayingVideo', { targetVideoId: this.videoId })
    },
  },
}
</script>
